namespace sv_f42cc10cc3ce4b85baf4b1608c360384;

// Service contracts
public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

// Mutable form models for Blazor data binding
public class PersonalInfoModel
{
    public string FullName { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";
    public string Address { get; set; } = "";

    public PersonalInfo ToRecord() => new(FullName, Email, Phone, Address);
}

public class WorkEntryModel
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public DateTime? StartDate { get; set; }
    public DateTime? EndDate { get; set; }
    public bool IsCurrent { get; set; }
    public string Description { get; set; } = "";

    public WorkEntry ToRecord() => new(Company, Title, StartDate ?? DateTime.Today, IsCurrent ? null : EndDate, Description);
}

public class ReferenceModel
{
    public string Name { get; set; } = "";
    public string Relationship { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";

    public Reference ToRecord() => new(Name, Relationship, Email, Phone);
}

.step-circle {
    width: 36px;
    height: 36px;
    border: 2px solid #dee2e6;
    background-color: #fff;
    font-weight: 600;
    font-size: 0.9rem;
    transition: all 0.2s;
}

.step-item.active .step-circle {
    border-color: #0d6efd;
    background-color: #0d6efd;
    color: #fff;
}

.step-item.completed .step-circle {
    border-color: #198754;
    background-color: #198754;
    color: #fff;
}

.step-item.pending .step-circle {
    border-color: #dee2e6;
    color: #adb5bd;
}

.step-label {
    font-size: 0.75rem;
    color: #6c757d;
}

.step-item.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step-item.completed .step-label {
    color: #198754;
}

@page "/apply"
@rendermode InteractiveServer
@using sv_f42cc10cc3ce4b85baf4b1608c360384.Components.JobApplication
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    @if (submittedId.HasValue)
    {
        <div class="alert alert-success text-center py-5">
            <h4 class="alert-heading">Application Submitted Successfully!</h4>
            <p class="mb-0">Your application ID is <strong>#@submittedId</strong>.</p>
            <p class="text-muted mt-2">Thank you for applying. We will be in touch.</p>
        </div>
    }
    else
    {
        <StepIndicator CurrentStep="currentStep" CompletedSteps="completedSteps"
                       OnStepClicked="GoToStep" />

        @if (!string.IsNullOrEmpty(errorMessage))
        {
            <div class="alert alert-danger">@errorMessage</div>
        }

        @switch (currentStep)
        {
            case 1:
                <PersonalInfoStep Model="personalInfo" />
                break;
            case 2:
                <WorkHistoryStep Entries="workEntries" />
                break;
            case 3:
                <ReferencesStep References="references" />
                break;
            case 4:
                <CoverLetterStep CoverLetter="@coverLetter"
                                 CoverLetterChanged="v => coverLetter = v" />
                break;
            case 5:
                <ReviewStep Personal="personalInfo" WorkEntries="workEntries"
                            References="references" CoverLetter="@coverLetter"
                            OnEditSection="GoToStep" />
                break;
        }

        <div class="d-flex justify-content-between mt-4">
            @if (currentStep > 1)
            {
                <button class="btn btn-outline-secondary" @onclick="PreviousStep"
                        disabled="@isProcessing">
                    Back
                </button>
            }
            else
            {
                <div></div>
            }

            @if (currentStep < 5)
            {
                <button class="btn btn-primary" @onclick="NextStep" disabled="@isProcessing">
                    @if (isProcessing)
                    {
                        <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                    }
                    Next
                </button>
            }
            else
            {
                <button class="btn btn-success" @onclick="SubmitApplication"
                        disabled="@isProcessing">
                    @if (isProcessing)
                    {
                        <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                    }
                    Submit Application
                </button>
            }
        </div>
    }
</div>

@code {
    private int currentStep = 1;
    private HashSet<int> completedSteps = new();
    private string? errorMessage;
    private bool isProcessing;
    private int? submittedId;

    private PersonalInfoModel personalInfo = new();
    private List<WorkEntryModel> workEntries = [new()];
    private List<ReferenceModel> references = [new(), new()];
    private string coverLetter = "";

    private void GoToStep(int step)
    {
        errorMessage = null;
        currentStep = step;
    }

    private void PreviousStep()
    {
        errorMessage = null;
        currentStep--;
    }

    private async Task NextStep()
    {
        errorMessage = null;
        isProcessing = true;

        try
        {
            if (!await ValidateCurrentStep())
                return;

            completedSteps.Add(currentStep);
            currentStep++;
        }
        finally
        {
            isProcessing = false;
        }
    }

    private async Task<bool> ValidateCurrentStep()
    {
        switch (currentStep)
        {
            case 1:
                if (string.IsNullOrWhiteSpace(personalInfo.FullName) ||
                    string.IsNullOrWhiteSpace(personalInfo.Email) ||
                    string.IsNullOrWhiteSpace(personalInfo.Phone) ||
                    string.IsNullOrWhiteSpace(personalInfo.Address))
                {
                    errorMessage = "Please fill in all required fields.";
                    return false;
                }
                if (!await ApplicationService.ValidateEmailAsync(personalInfo.Email))
                {
                    errorMessage = "The email address is not valid.";
                    return false;
                }
                return true;

            case 2:
                if (!workEntries.Any(e =>
                        !string.IsNullOrWhiteSpace(e.Company) &&
                        !string.IsNullOrWhiteSpace(e.Title) &&
                        e.StartDate.HasValue))
                {
                    errorMessage = "Please complete at least one work entry with company, title, and start date.";
                    return false;
                }
                return true;

            case 3:
                if (!references.Any(r =>
                        !string.IsNullOrWhiteSpace(r.Name) &&
                        !string.IsNullOrWhiteSpace(r.Email)))
                {
                    errorMessage = "Please provide at least one reference with name and email.";
                    return false;
                }
                return true;

            case 4:
                if (string.IsNullOrWhiteSpace(coverLetter))
                {
                    errorMessage = "Please write a cover letter.";
                    return false;
                }
                return true;

            default:
                return true;
        }
    }

    private async Task SubmitApplication()
    {
        errorMessage = null;
        isProcessing = true;

        try
        {
            var application = new JobApplication(
                personalInfo.ToRecord(),
                new WorkHistory(workEntries.Select(e => e.ToRecord()).ToList()),
                references
                    .Where(r => !string.IsNullOrWhiteSpace(r.Name))
                    .Select(r => r.ToRecord())
                    .ToList(),
                coverLetter
            );

            submittedId = await ApplicationService.SubmitApplicationAsync(application);
        }
        catch (Exception ex)
        {
            errorMessage = $"Submission failed: {ex.Message}";
        }
        finally
        {
            isProcessing = false;
        }
    }
}

