    <div class="d-flex justify-content-between position-relative">
        @for (int i = 0; i < StepNames.Count; i++)
        {
            var step = i + 1;
            var isCompleted = CompletedSteps.Contains(step);
            var isCurrent = step == CurrentStep;
            var cssClass = isCurrent ? "active" : isCompleted ? "completed" : "pending";

            <div class="step-item text-center @cssClass"
                 style="flex: 1; cursor: @(isCompleted ? "pointer" : "default")"
                 @onclick="() => HandleStepClick(step)">
                <div class="step-circle mx-auto mb-1 d-flex align-items-center justify-content-center rounded-circle">
                    @if (isCompleted && !isCurrent)
                    {
                        <span>✓</span>
                    }
                    else
                    {
                        <span>@step</span>
                    }
                </div>
                <small class="step-label d-none d-md-block">@StepNames[i]</small>
            </div>
        }
    </div>
</div>

@code {
    [Parameter] public int CurrentStep { get; set; }
    [Parameter] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }

    private static readonly List<string> StepNames =
    [
        "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"
    ];

    private async Task HandleStepClick(int step)
    {
        if (CompletedSteps.Contains(step))
        {
